example.code:
variables
{
  dword myCertHdl;

  struct SspBitmap
  {
    char  name[16];
    dword aid;
    dword len;
    byte  ssp[10];
    byte  msk[10];
    byte  chain;
  };

  struct SspBitmap ssp =
  {
    "CAM",
    0x24,
    3,
    { 0x01, 0x02, 0x00 },
    { 0xff, 0x02, 0x00 },
    1
  };
}

on start
{
  myCertHdl = C2xSecCertificateGetHandle("MyCert");

  write("SSP %s: %d", ssp.name,
    C2xSecCertificateValidAppSspBitmap(myCertHdl, ssp.aid,
    ssp.len, ssp.ssp, ssp.msk, ssp.chain)) ;
}
